/** 60갑자 일주 index. (stem, branch) → 0..59. */
export function iljuIndex(dayStem: number, dayBranch: number): number {
  for (let i = 0; i < 60; i++) {
    if (i % 10 === dayStem && i % 12 === dayBranch) return i;
  }
  throw new Error(`invalid ilju pair: stem=${dayStem} branch=${dayBranch}`);
}

export function iljuAt(dayStem: number, dayBranch: number): IljuEntry {
  return ILJU_ENTRIES[iljuIndex(dayStem, dayBranch)];
}
